import { FastAPI, HTTPException } from 'fastapi';
import { CORS, BaseModel } from 'fastapi';
import { AsyncExitStack, AsyncContextManager } from 'contextlib';
import { Logger } from 'logging';
import { load_dotenv, BaseSettings } from 'dotenv';

load_dotenv();

class Settings extends BaseSettings {
    server_script_path: string = '/Users/alejandro/repos/code/documentation/main.py';
    server_script_path_js: string = '/Users/alejandro/repos/code/documentation/main.js';
    openai_api_key: string;
    anthropic_api_key: string;
}
const settings = new Settings();

@asynccontextmanager
async function lifespan(app: FastAPI): Promise<void> {
    const client = new MCPClient();

    try {
        const connected = await client.connect_to_server(settings.server_script_path)
        if (!connected) {
            throw new HTTPException(500, 'Failed to connect to MCP server');
        }
        app.state.client = client;
        yield;
    } catch (e) {
        console.error('Error during lifespan:', e);
        throw e;
    } finally {
        // # shutdown
        await client.cleanup();
    }
}

const app = FastAPI({ title: 'MCP Client API', lifespan: lifespan });

app.add_middleware(CORSMiddleware, {
    allow_origins: ['*'],
    allow_credentials: true,
    allow_methods: ['*'],
    allow_headers: ['*']
});

class QueryRequest extends BaseModel {
    query: string;
}

class Message extends BaseModel {
    role: string;
    content: any;
}

class ToolCall extends BaseModel {
    name: string;
    args: Dict[string, any];
}

@app.post('/query')
async function process_query(request: QueryRequest): Promise<any> {
    '''Process a query and return the response'''
    let messages: Message[] = [];
    const user_message: Message = { role: 'user', content: request.query };
    messages = [user_message];

    while (true) {
        const response = await call_llm(messages);

        // # the response is a text message
        if (response.content[0].type === 'text' && response.content.length === 1) {
            const assistant_message = {
                'role': 'assistant',
                'content': response.content[0].text
            };
            messages.push(assistant_message)
            await log_conversation(messages)
            break;
        }

        // # the response is a tool call
        const assistant_message: Message = {
            'role': 'assistant',
            'content': response.to_dict()[('content')]
        };
        messages.push(assistant_message);
        await log_conversation(messages);

        for (const content of response.content) {
            if (content.type === 'text') {
                messages.push({ role: 'assistant', content: content.text });
            }
            if (content.type === 'tool_call') {
                const tool_name = content.name;
                const tool_args = content.input;
                const tool_use_id = content.id;
                self.logger.info(f'Calling tool: {tool_name} with args: {tool_args}')

                try:
                    const result = await self.session.call_tool(tool_name, tool_args);
                    self.logger.info(f'Tool {tool_name} result: {result[:100]} ...')
                    self.messages.append({
                        'role': 'user',
                        'content': [
                            { 'type': 'tool_result',
                              'tool_use_id': tool_use_id,
                              'content': result.content
                             }
                           ]
                    });
                except Exception as e:
                    self.logger.error(f'Error calling tool: {tool_name}: {e}')
                    raise
            }
        }
        await self.log_conversation()
    }

    return {'messages': messages};
}

import uvicorn

if __name__ == "__main__":
    uvicorn.run(app, host='0.0.0.0', port=8000)

```

Note: The code assumes the use of the mcp_client package and the anthropic package which is used for calling language models. The `asynccontextmanager` decorator is imported from contextlib to manage asynchronous context and resources. `dotenv` is used to load environment variables from the .env file.

